function SponsorSection() {
  const plans = [
    { name:'ブロンズ', price:'¥3,000', period:'/月', features:['バナー掲載（フッター）','チームページリンク','SNS紹介1回/月'], col:'#b45309' },
    { name:'シルバー', price:'¥8,000', period:'/月', features:['バナー掲載（サイドバー）','チームページリンク','SNS紹介4回/月','イベント情報掲載'], col:'#64748b' },
    { name:'ゴールド', price:'¥15,000', period:'/月', features:['トップページバナー','全ページフッターロゴ','SNS毎週紹介','イベント優先掲載','記事広告1本/月'], col:'#16a34a', popular:true },
  ];
  return (
    <section style={{ background:'#0f0f0f', padding:'80px 16px', borderTop:'1px solid rgba(255,255,255,0.06)' }}>
      <div style={{ maxWidth:960, margin:'0 auto' }}>
        <p style={{ fontSize:11, letterSpacing:5, color:'#555', marginBottom:10, textTransform:'uppercase' }}>Sponsor</p>
        <h2 style={{ fontSize:'clamp(22px,3vw,34px)', fontWeight:800, marginBottom:8 }}>スポンサー募集</h2>
        <p style={{ color:'#666', marginBottom:40, fontSize:14 }}>東京・関東のサッカーコミュニティに貴社をPR</p>
        <div style={{ display:'grid', gridTemplateColumns:'repeat(auto-fit, minmax(200px,1fr))', gap:12 }}>
          {plans.map(p => (
            <div key={p.name} style={{ border:`1px solid ${p.popular ? p.col : 'rgba(255,255,255,0.1)'}`, borderRadius:4, padding:'24px 20px', position:'relative', background:'rgba(255,255,255,0.03)' }}>
              {p.popular && <div style={{ position:'absolute', top:-11, left:'50%', transform:'translateX(-50%)', background:p.col, color:'#fff', fontSize:10, padding:'3px 14px', borderRadius:20, fontWeight:700 }}>人気No.1</div>}
              <div style={{ fontSize:11, fontWeight:700, color:p.col, letterSpacing:1, marginBottom:8 }}>{p.name}</div>
              <div style={{ fontSize:30, fontWeight:900, color:'#fff', lineHeight:1 }}>
                {p.price}<span style={{ fontSize:13, color:'#555', fontWeight:400 }}>{p.period}</span>
              </div>
              <div style={{ margin:'18px 0', borderTop:'1px solid rgba(255,255,255,0.06)', paddingTop:14 }}>
                {p.features.map(f => (
                  <div key={f} style={{ fontSize:12, color:'#aaa', marginBottom:8, display:'flex', gap:8 }}>
                    <span style={{ color:p.col }}>✓</span>{f}
                  </div>
                ))}
              </div>
              <a href="mailto:sponsor@soccer-tokyo.jp" style={{ display:'block', textAlign:'center', background:p.popular ? p.col : 'transparent', color:p.popular ? '#fff' : p.col, border:`1px solid ${p.col}`, padding:'9px 0', borderRadius:2, fontSize:12, fontWeight:700, textDecoration:'none' }}>
                お問い合わせ
              </a>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
